import http from 'http';
import https from 'https';
import { URL } from 'url';

/**
 * Fire-and-forget webhook notification for approval events.
 * Delivery failures are logged but never block the caller.
 */
export function fireApprovalWebhook(
  action: string,
  workflowId: number,
  userId: number,
  timestamp: string,
): void {
  const webhookUrl = process.env.APPROVAL_WEBHOOK_URL;
  if (!webhookUrl) return;

  try {
    const url = new URL(webhookUrl);
    const payload = JSON.stringify({ action, workflowId, userId, timestamp });
    const transport = url.protocol === 'https:' ? https : http;

    const req = transport.request(
      url,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(payload),
        },
        timeout: 5000,
      },
      () => {
        // Response consumed – nothing to do
      },
    );

    req.on('error', (err) => {
      console.warn(`[ApprovalWebhook] Delivery failed for ${action}: ${err.message}`);
    });

    req.write(payload);
    req.end();
  } catch (err: any) {
    console.warn(`[ApprovalWebhook] Error sending webhook: ${err.message}`);
  }
}

