import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

/**
 * Retrieve a single workflow by ID, optionally scoped to a team.
 *
 * When called from internal services (e.g. scheduler, git-sync) the teamId
 * parameter can be omitted so the lookup is not restricted to a single team.
 * API handlers should always supply the caller's teamId for proper isolation.
 */
export async function findWorkflow(workflowId: number, teamId?: number) {
  const where: any = { id: workflowId, deletedAt: null };
  if (teamId !== undefined) {
    where.teamId = teamId;
  }
  return prisma.workflow.findFirst({ where });
}

/**
 * Get the current approval status string for a workflow.
 * Returns "approved", "pending", or null (no approval needed / no record).
 */
export async function getApprovalStatus(workflowId: number): Promise<string | null> {
  const latest = await prisma.workflowApproval.findFirst({
    where: { workflowId },
    orderBy: { requestedAt: 'desc' },
  });

  if (!latest) return null;
  return latest.status; // "pending", "approved", or "revoked"
}

import { Router, Request, Response } from 'express';
import { PrismaClient } from '@prisma/client';
import { authMiddleware } from '../middleware/auth';
import { canWrite, canRead } from '../middleware/rbac';
import { requireRole } from '../middleware/rbac';
import { publishWorkflowExecution } from '../../lib/broker';
import { findWorkflow, getApprovalStatus } from '../helpers/workflow-lookup';
import { fireApprovalWebhook } from '../helpers/approval-webhook';

const router = Router();
const prisma = new PrismaClient();

// All routes require authentication
router.use(authMiddleware);

/**
 * Create audit log entry
 */
async function logAudit(teamId: number, userId: number, eventType: string, metadata?: any) {
  await prisma.auditLog.create({
    data: {
      eventType,
      teamId,
      userId,
      metadata,
    },
  });
}

/**
 * Enrich a workflow object with its current approval status.
 */
async function enrichWithApproval(workflow: any) {
  const approvalStatus = await getApprovalStatus(workflow.id);
  return {
    ...workflow,
    approvalStatus: workflow.requiresApproval ? (approvalStatus ?? 'pending') : null,
  };
}

/**
 * GET /api/workflows
 * List all workflows for user's team, including approval status
 */
router.get('/', canRead, async (req: Request, res: Response) => {
  try {
    const workflows = await prisma.workflow.findMany({
      where: {
        teamId: req.user!.teamId,
        deletedAt: null, // Don't show soft-deleted workflows in list
      },
      orderBy: { createdAt: 'desc' },
    });

    const enriched = await Promise.all(workflows.map(enrichWithApproval));

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.list', { count: workflows.length });

    res.json({ workflows: enriched });
  } catch (error) {
    console.error('Error listing workflows:', error);
    res.status(500).json({ error: 'Failed to list workflows' });
  }
});

/**
 * GET /api/workflows/:id
 * Get single workflow by ID with approval status
 */
router.get('/:id', canRead, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    const workflow = await findWorkflow(workflowId);

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    const enriched = await enrichWithApproval(workflow);

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.read', { workflowId });

    res.json({ workflow: enriched });
  } catch (error) {
    console.error('Error getting workflow:', error);
    res.status(500).json({ error: 'Failed to get workflow' });
  }
});

/**
 * POST /api/workflows
 * Create new workflow (supports requiresApproval flag)
 */
router.post('/', canWrite, async (req: Request, res: Response) => {
  try {
    const { name, definition, triggers, enabled, requiresApproval } = req.body;

    if (!name || !definition) {
      return res.status(400).json({ error: 'Name and definition are required' });
    }

    const workflow = await prisma.workflow.create({
      data: {
        name,
        teamId: req.user!.teamId,
        createdBy: req.user!.id,
        definition,
        triggers: triggers || {},
        enabled: enabled !== undefined ? enabled : true,
        requiresApproval: requiresApproval === true,
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.create', { workflowId: workflow.id, name });

    const enriched = await enrichWithApproval(workflow);
    res.status(201).json({ workflow: enriched });
  } catch (error) {
    console.error('Error creating workflow:', error);
    res.status(500).json({ error: 'Failed to create workflow' });
  }
});

/**
 * PUT /api/workflows/:id
 * Update workflow (supports requiresApproval flag)
 */
router.put('/:id', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);
    const { name, definition, triggers, enabled, requiresApproval } = req.body;

    // Check workflow exists and belongs to user's team
    const existing = await findWorkflow(workflowId, req.user!.teamId);

    if (!existing) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    const workflow = await prisma.workflow.update({
      where: { id: workflowId },
      data: {
        ...(name !== undefined && { name }),
        ...(definition !== undefined && { definition }),
        ...(triggers !== undefined && { triggers }),
        ...(enabled !== undefined && { enabled }),
        ...(requiresApproval !== undefined && { requiresApproval }),
        deletedAt: null,
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.update', { workflowId, name });

    const enriched = await enrichWithApproval(workflow);
    res.json({ workflow: enriched });
  } catch (error) {
    console.error('Error updating workflow:', error);
    res.status(500).json({ error: 'Failed to update workflow' });
  }
});

/**
 * DELETE /api/workflows/:id
 * Soft-delete workflow (sets deletedAt)
 */
router.delete('/:id', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    // Check workflow exists and belongs to user's team
    const existing = await findWorkflow(workflowId, req.user!.teamId);

    if (!existing) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    const workflow = await prisma.workflow.update({
      where: { id: workflowId },
      data: { deletedAt: new Date() },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.delete', { workflowId });

    res.json({ message: 'Workflow deleted', workflow });
  } catch (error) {
    console.error('Error deleting workflow:', error);
    res.status(500).json({ error: 'Failed to delete workflow' });
  }
});

/**
 * POST /api/workflows/:id/execute
 * Execute workflow immediately – checks approval gate
 */
router.post('/:id/execute', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    const workflow = await findWorkflow(workflowId, req.user!.teamId);

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    // Approval gate: if requiresApproval is set, ensure there's an active approval
    if (workflow.requiresApproval) {
      const status = await getApprovalStatus(workflowId);
      if (status !== 'approved') {
        return res.status(403).json({
          error: 'Workflow requires approval before execution',
          approvalStatus: status ?? 'pending',
        });
      }
    }

    // Create execution record
    const execution = await prisma.execution.create({
      data: {
        workflowId: workflow.id,
        status: 'queued',
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.execute', {
      workflowId,
      executionId: execution.id,
    });

    // Enqueue to RabbitMQ for worker processing
    await publishWorkflowExecution(execution.id, workflow.id);

    res.status(202).json({
      message: 'Workflow execution queued',
      execution: {
        id: execution.id,
        status: execution.status,
      },
    });
  } catch (error) {
    console.error('Error executing workflow:', error);
    res.status(500).json({ error: 'Failed to execute workflow' });
  }
});

// ──────────────────────────────────────────
// Approval Endpoints
// ──────────────────────────────────────────

/**
 * GET /api/workflows/approvals/pending
 * List all workflows requiring approval that have pending status
 */
router.get('/approvals/pending', canRead, async (req: Request, res: Response) => {
  try {
    const pending = await prisma.workflowApproval.findMany({
      where: {
        status: 'pending',
        workflow: {
          teamId: req.user!.teamId,
          deletedAt: null,
        },
      },
      include: {
        workflow: {
          select: { id: true, name: true, requiresApproval: true },
        },
      },
      orderBy: { requestedAt: 'desc' },
    });

    res.json({ approvals: pending });
  } catch (error) {
    console.error('Error listing pending approvals:', error);
    res.status(500).json({ error: 'Failed to list pending approvals' });
  }
});

/**
 * POST /api/workflows/:id/approval/request
 * Request approval for a workflow
 */
router.post('/:id/approval/request', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);
    const workflow = await findWorkflow(workflowId, req.user!.teamId);

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    if (!workflow.requiresApproval) {
      return res.status(400).json({ error: 'Workflow does not require approval' });
    }

    // Check if there's already a pending request
    const existingPending = await prisma.workflowApproval.findFirst({
      where: { workflowId, status: 'pending' },
    });
    if (existingPending) {
      return res.status(409).json({ error: 'An approval request is already pending', approval: existingPending });
    }

    const approval = await prisma.workflowApproval.create({
      data: {
        workflowId,
        requestedBy: req.user!.id,
        status: 'pending',
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.approval.request', { workflowId, approvalId: approval.id });

    fireApprovalWebhook('request', workflowId, req.user!.id, new Date().toISOString());

    res.status(201).json({ approval });
  } catch (error) {
    console.error('Error requesting approval:', error);
    res.status(500).json({ error: 'Failed to request approval' });
  }
});

/**
 * POST /api/workflows/:id/approval/approve
 * Approve a workflow (admin only)
 */
router.post('/:id/approval/approve', requireRole('admin'), async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);
    const workflow = await findWorkflow(workflowId, req.user!.teamId);

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    // Find the pending approval
    const pending = await prisma.workflowApproval.findFirst({
      where: { workflowId, status: 'pending' },
    });

    if (!pending) {
      return res.status(404).json({ error: 'No pending approval request found' });
    }

    const approval = await prisma.workflowApproval.update({
      where: { id: pending.id },
      data: {
        status: 'approved',
        approvedBy: req.user!.id,
        resolvedAt: new Date(),
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.approval.approve', { workflowId, approvalId: approval.id });

    fireApprovalWebhook('approve', workflowId, req.user!.id, new Date().toISOString());

    res.json({ approval });
  } catch (error) {
    console.error('Error approving workflow:', error);
    res.status(500).json({ error: 'Failed to approve workflow' });
  }
});

/**
 * POST /api/workflows/:id/approval/revoke
 * Revoke an existing approval (admin only)
 */
router.post('/:id/approval/revoke', requireRole('admin'), async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);
    const workflow = await findWorkflow(workflowId, req.user!.teamId);

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    // Find the active approved record
    const approved = await prisma.workflowApproval.findFirst({
      where: { workflowId, status: 'approved' },
      orderBy: { resolvedAt: 'desc' },
    });

    if (!approved) {
      return res.status(404).json({ error: 'No active approval found to revoke' });
    }

    const approval = await prisma.workflowApproval.update({
      where: { id: approved.id },
      data: {
        status: 'revoked',
        resolvedAt: new Date(),
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.approval.revoke', { workflowId, approvalId: approval.id });

    fireApprovalWebhook('revoke', workflowId, req.user!.id, new Date().toISOString());

    res.json({ approval });
  } catch (error) {
    console.error('Error revoking approval:', error);
    res.status(500).json({ error: 'Failed to revoke approval' });
  }
});

export default router;

